/*@ Import Coq Require Import array_min */

int array_min(int n, int *a)
/*@ With l
    Require
      1 <= n &&
      Zlength(l) == n &&
      IntArray::full(a, n, l)
    Ensure
      __return == min_list_nonempty(l) &&
      IntArray::full(a, n, l)
*/
{
    int i;
    int ret = a[0];

    for (i = 1; i < n; ++i) {
        if (a[i] < ret) {
            ret = a[i];
        }
    }

    return ret;
}

